$slotPlayTarget = static function (array $game) use ($loggedIn): string {
    $gid = (string) ($game['game_id'] ?? '');
    $play = '/play?game_id=' . rawurlencode($gid) . '&mode=real&wallet=main';
    if ($loggedIn) {
        return $play;
    }
    return '#login';
};
$slotDemoHref = static function (array $game): string {
    $gid = (string) ($game['game_id'] ?? '');

    return '/play?game_id=' . rawurlencode($gid) . '&mode=fun';
};

$slotRepairMojibake = static function (string $value): string {
    return strtr($value, [
        'Ã‡' => 'Ç', 'Ã–' => 'Ö', 'Ãœ' => 'Ü', 'Ä°' => 'İ', 'Åž' => 'Ş', 'Äž' => 'Ğ',
        'Ã§' => 'ç', 'Ã¶' => 'ö', 'Ã¼' => 'ü', 'Ä±' => 'ı', 'ÅŸ' => 'ş', 'ÄŸ' => 'ğ',
    ]);
};

/** @return string BEM modifier sınıfı (provider-badge--jackpot vb.) */
$providerBadgeModifierClass = static function (string $badge) use ($slotRepairMojibake): string {
    $badge = $slotRepairMojibake($badge);
    $n = strtoupper(preg_replace('/\s+/u', ' ', trim($badge)));
    $n = str_replace(['İ', 'ı'], ['I', 'I'], $n);
    if (strpos($n, 'EN') !== false && strpos($n, 'IYI') !== false) {
        return 'provider-badge--best';
    }
    if ($n === 'JACKPOT') {
        return 'provider-badge--jackpot';
    }
    if ($n === 'SICAK') {
        return 'provider-badge-hot';
    }
    if ($n === 'PROMOSYON') {
        return 'provider-badge--promo';
    }
    if ($n === 'OZEL' || $n === 'ÖZEL') {
        return 'provider-badge--special';
    }
    if ($n === 'YENI' || $n === 'YENİ') {
        return 'provider-badge-new';
    }
    return 'provider-badge--default';
};

$providerBadgeBlockClass = static function (string $badge) use ($slotRepairMojibake): string {
    $badge = $slotRepairMojibake($badge);
    $n = strtoupper(preg_replace('/\s+/u', ' ', trim($badge)));
    $n = str_replace(['İ', 'ı'], ['I', 'I'], $n);
    if (strpos($n, 'EN') !== false && strpos($n, 'IYI') !== false) {
        return 'badge-top';
    }
    if ($n === 'JACKPOT') {
        return 'badge-jackpot';
    }
    if ($n === 'SICAK') {
        return 'badge-hot';
    }
    if ($n === 'PROMOSYON') {
        return 'badge-promo';
    }
    if ($n === 'OZEL' || $n === 'ÖZEL') {
        return 'badge-exclusive';
    }
    if ($n === 'ORTAK') {
        return 'badge-ortak';
    }
    return '';
};

$providerBadgeStyle = static function (string $badgeClass): string {
    if ($badgeClass === 'badge-hot') {
        return 'background: rgb(227, 32, 32); color: rgb(255, 255, 255);';
    }
    if ($badgeClass === 'badge-jackpot') {
        return 'background: rgb(123, 100, 24); color: rgb(255, 255, 255);';
    }
    if ($badgeClass === 'badge-ortak') {
        return 'background: rgb(112, 0, 255); color: rgb(255, 255, 255);';
    }
    if ($badgeClass === 'badge-promo') {
        return 'background: rgb(34, 157, 136); color: rgb(255, 255, 255);';
    }
    if ($badgeClass === 'badge-exclusive') {
        return 'background: rgb(76, 163, 84); color: rgb(255, 255, 255);';
    }
    return 'background: rgb(110, 58, 133); color: rgb(255, 255, 255);';
};

